    #[test]
    fn verify_valid_signature() {
        let secret = "REDACTED";
        let timestamp = "1531420618";
        let body = b"REDACTED&team_id=T1DC2JH3J&team_domain=testteamnow&channel_id=G8LX6B8TU&channel_name=mpmulti&user_id=U2CERLKJA&user_name=roadrunner&command=%2Fwebhook-collect&text=&response_url=https%3A%2F%2Fhooks.slack.com%2Fcommands%2FT1DC2JH3J%2F397700885554%2F96rGlfmibIGlgcZRskXaIFfN&trigger_id=398738663015.47445629121.803a0bc887a14d10d2c659f2945b6e92";

        // Compute expected signature.
        use hmac::Mac;
        let mut mac = HmacSha256::new_from_slice(secret.as_bytes()).unwrap();
        mac.update(format!("v0:{timestamp}:").as_bytes());
        mac.update(body);
        let result = mac.finalize().into_bytes();
        let hex: String = result.iter().map(|b| format!("{b:02x}")).collect();
        let signature = format!("v0={hex}");

        assert!(verify_signature(secret, timestamp, body, &signature));
    }

