    fn extract_form_payload_finds_payload() {
        let body = "token=abc&payload=%7B%22type%22%3A%22test%22%7D&other=val";
        let result = extract_form_payload(body);
        assert_eq!(result, Some(r#"{"type":"test"}"#.to_string()));
    }

