            Arc::new(std::sync::RwLock::new(std::collections::HashMap::new()));
        let body = b"text=hello&user_id=U123&channel_id=C456";
        let result = handle_verified_command_webhook("acct1", body, &accounts).await;
        assert!(result.is_err());
